import{_ as a,c as l,a0 as i,o as r}from"./chunks/framework.B6JXc2q-.js";const p=JSON.parse('{"title":"认证恢复状态机规范","description":"","frontmatter":{},"headers":[],"relativePath":"spec/auth_recovery_state_machine.md","filePath":"spec/auth_recovery_state_machine.md"}'),o={name:"spec/auth_recovery_state_machine.md"};function t(d,e,n,s,c,u){return r(),l("div",null,e[0]||(e[0]=[i(`<h1 id="认证恢复状态机规范" tabindex="-1">认证恢复状态机规范 <a class="header-anchor" href="#认证恢复状态机规范" aria-label="Permalink to &quot;认证恢复状态机规范&quot;">​</a></h1><p>版本：v1.1<br> 状态：行为冻结文档<br> 最后更新：2026-04-09<br> 适用范围：<code>xiaomusic/auth.py</code> 内认证错误判定、恢复链路与状态转移</p><hr><h2 id="_1-文档目的" tabindex="-1">1. 文档目的 <a class="header-anchor" href="#_1-文档目的" aria-label="Permalink to &quot;1. 文档目的&quot;">​</a></h2><p>本文档冻结当前 <code>auth.py</code> 恢复状态机的真实行为边界，并同步当前已知验收结论。</p><p>本文档解决：</p><ul><li>probe failure / auth error / manual login 之间的语义边界</li><li>suspect / non-destructive recovery / clear+rebuild / runtime reload 的关系</li><li>locked / manual login required 的收紧条件</li><li>当前 fresh session 修补后的主路径结论属于哪一层</li></ul><p>本文档不解决：</p><ul><li>spec rebuild 全量验收</li><li>singleflight 全量实机闭环</li><li>fallback 全量验收</li><li>auth / playback 交叉边界</li></ul><hr><h2 id="_2-范围与非目标" tabindex="-1">2. 范围与非目标 <a class="header-anchor" href="#_2-范围与非目标" aria-label="Permalink to &quot;2. 范围与非目标&quot;">​</a></h2><h3 id="_2-1-范围" tabindex="-1">2.1 范围 <a class="header-anchor" href="#_2-1-范围" aria-label="Permalink to &quot;2.1 范围&quot;">​</a></h3><ul><li>auth.py 内认证错误判定逻辑</li><li>suspect 状态与升级条件</li><li>non-destructive recovery（Phase A / Phase B）</li><li>clear short session 与 rebuild 流程</li><li>runtime reload / <code>_try_login()</code> 主路径与状态转移</li><li>auth_mode：healthy / degraded / locked</li></ul><h3 id="_2-2-非目标" tabindex="-1">2.2 非目标 <a class="header-anchor" href="#_2-2-非目标" aria-label="Permalink to &quot;2.2 非目标&quot;">​</a></h3><ul><li>不讨论未来大重构方案</li><li>不替代 <code>docs/spec/auth_runtime_recovery.md</code> 的主线路径说明</li><li>不把局部通过扩写成 spec rebuild 全量通过</li></ul><hr><h2 id="_3-当前恢复链总览" tabindex="-1">3. 当前恢复链总览 <a class="header-anchor" href="#_3-当前恢复链总览" aria-label="Permalink to &quot;3. 当前恢复链总览&quot;">​</a></h2><p>当前自动恢复不是单一路径，而是分层恢复链：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>auth_call 捕获 auth error</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>判断 should_clear_short_session</span></span>
<span class="line"><span>    ├─ first_suspect → non-destructive recovery</span></span>
<span class="line"><span>    │       ├─ Phase A（基于现有 short session 的 runtime rebuild / verify）</span></span>
<span class="line"><span>    │       │       ├─ success → 重试原请求</span></span>
<span class="line"><span>    │       │       └─ strong evidence → 升级到 clear+rebuild</span></span>
<span class="line"><span>    │       └─ Phase B（轻量 verify）</span></span>
<span class="line"><span>    │               ├─ success → 重试原请求</span></span>
<span class="line"><span>    │               └─ failed → 抛出错误，不 clear</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ consecutive_auth_error_* → clear+rebuild（受 singleflight 保护）</span></span>
<span class="line"><span>    └─ degraded + token available → runtime reload / \`_try_login()\` 主路径</span></span></code></pre></div><p>关键区分：</p><ul><li><strong>probe failure 只是退化触发器，不等于 manual login</strong></li><li><strong>进入 degraded 不等于进入 locked</strong></li><li><strong>manual_login_required 只应在有强人工介入证据时成立</strong></li><li><strong>当前 fresh session 修补已经消除了“复用旧 session 导致 <code>login(false)</code>”这一类主断点</strong></li><li><strong>以上只覆盖当前主路径，不覆盖全部恢复分支</strong></li></ul><hr><h2 id="_4-状态定义" tabindex="-1">4. 状态定义 <a class="header-anchor" href="#_4-状态定义" aria-label="Permalink to &quot;4. 状态定义&quot;">​</a></h2><h3 id="_4-1-healthy" tabindex="-1">4.1 healthy <a class="header-anchor" href="#_4-1-healthy" aria-label="Permalink to &quot;4.1 healthy&quot;">​</a></h3><ul><li>语义：认证状态正常，业务请求可正常执行</li><li>进入条件：恢复链成功完成，runtime 可用</li><li>退出条件：auth error 或 probe failure 触发退化判定</li></ul><h3 id="_4-2-degraded" tabindex="-1">4.2 degraded <a class="header-anchor" href="#_4-2-degraded" aria-label="Permalink to &quot;4.2 degraded&quot;">​</a></h3><ul><li>语义：认证状态异常，部分能力可能不可用，但仍优先尝试自动恢复</li><li>进入条件： <ul><li><code>ensure_logged_in</code> 失败</li><li>keepalive / verify / probe 失败</li><li>runtime reload / <code>_try_login()</code> 主路径失败但未达到 locked 条件</li></ul></li><li>退出条件：恢复成功后转为 healthy</li></ul><p><strong>重要</strong>：probe failure 只是 degraded 的触发器，不等于 manual login required。</p><h3 id="_4-3-locked" tabindex="-1">4.3 locked <a class="header-anchor" href="#_4-3-locked" aria-label="Permalink to &quot;4.3 locked&quot;">​</a></h3><ul><li>语义：认证锁定，需要人工干预（扫码登录）</li><li>进入条件：长期态必需字段缺失或等价硬故障，自动恢复前提已不成立</li><li>不应由以下情况直接触发： <ul><li>单次 probe failure</li><li>单次 login-stage failure</li><li>单次 verify-stage failure</li><li>单次 network error</li></ul></li></ul><h3 id="_4-4-manual-login-required" tabindex="-1">4.4 manual_login_required <a class="header-anchor" href="#_4-4-manual-login-required" aria-label="Permalink to &quot;4.4 manual_login_required&quot;">​</a></h3><p><code>manual_login_required</code> 的语义已经收紧：</p><ul><li>只在有<strong>强人工介入证据</strong>时成立</li><li>例如长期态缺失、locked 已成立、或高层策略已明确要求扫码</li></ul><p>以下情况<strong>不应</strong>直接写成 <code>manual_login_required=true</code>：</p><ul><li>degraded</li><li>单次 runtime verify 失败</li><li><code>_try_login()</code> 主路径中的一次失败</li><li>auto runtime reload 的一次失败</li></ul><hr><h2 id="_5-auth-error-检测与-suspect-机制" tabindex="-1">5. auth error 检测与 suspect 机制 <a class="header-anchor" href="#_5-auth-error-检测与-suspect-机制" aria-label="Permalink to &quot;5. auth error 检测与 suspect 机制&quot;">​</a></h2><h3 id="_5-1-错误分类" tabindex="-1">5.1 错误分类 <a class="header-anchor" href="#_5-1-错误分类" aria-label="Permalink to &quot;5.1 错误分类&quot;">​</a></h3><p><code>auth_call</code> 捕获异常后的分流仍然是：</p><table tabindex="0"><thead><tr><th>错误类型</th><th>处理方式</th></tr></thead><tbody><tr><td>network error</td><td>直接抛出，不进入 auth 恢复主链</td></tr><tr><td>非严格 auth error</td><td>直接抛出，不进入恢复链</td></tr><tr><td>严格 auth error</td><td>进入 suspect 判定与恢复链</td></tr></tbody></table><h3 id="_5-2-suspect-语义" tabindex="-1">5.2 suspect 语义 <a class="header-anchor" href="#_5-2-suspect-语义" aria-label="Permalink to &quot;5.2 suspect 语义&quot;">​</a></h3><p>suspect 的目的仍然是：</p><ul><li>避免首次 auth error 就立即 clear short session</li><li>把首次异常与连续异常区分开</li><li>为 non-destructive recovery 提供缓冲层</li></ul><h3 id="_5-3-升级条件" tabindex="-1">5.3 升级条件 <a class="header-anchor" href="#_5-3-升级条件" aria-label="Permalink to &quot;5.3 升级条件&quot;">​</a></h3><ul><li><code>first_suspect</code>：优先走 non-destructive recovery</li><li><code>consecutive_auth_error_*</code>：升级到 clear+rebuild</li><li>strong evidence：在同一轮内从 Phase A 升级到 clear+rebuild</li></ul><hr><h2 id="_6-non-destructive-recovery-规范" tabindex="-1">6. non-destructive recovery 规范 <a class="header-anchor" href="#_6-non-destructive-recovery-规范" aria-label="Permalink to &quot;6. non-destructive recovery 规范&quot;">​</a></h2><h3 id="_6-1-phase-a" tabindex="-1">6.1 Phase A <a class="header-anchor" href="#_6-1-phase-a" aria-label="Permalink to &quot;6.1 Phase A&quot;">​</a></h3><p>目标：</p><ul><li>使用 auth.json 中已有 short session 重建 runtime</li><li>优先验证“现有 short session 是否还能撑起 runtime”</li></ul><p>当前语义：</p><ul><li>success：重试原请求</li><li>verify 失败且 auth failure detected：可升级为 strong evidence</li><li>失败但证据不足：不立即 clear</li></ul><h3 id="_6-2-phase-b" tabindex="-1">6.2 Phase B <a class="header-anchor" href="#_6-2-phase-b" aria-label="Permalink to &quot;6.2 Phase B&quot;">​</a></h3><p>目标：</p><ul><li>对当前 runtime 做轻量 verify</li><li>不修改状态，只做保守验证</li></ul><p>当前语义：</p><ul><li>success：重试原请求</li><li>failed：抛错，不 clear，不直接导向 manual login</li></ul><hr><h2 id="_7-clear-rebuild-与-runtime-reload-的关系" tabindex="-1">7. clear + rebuild 与 runtime reload 的关系 <a class="header-anchor" href="#_7-clear-rebuild-与-runtime-reload-的关系" aria-label="Permalink to &quot;7. clear + rebuild 与 runtime reload 的关系&quot;">​</a></h2><h3 id="_7-1-clear-rebuild" tabindex="-1">7.1 clear + rebuild <a class="header-anchor" href="#_7-1-clear-rebuild" aria-label="Permalink to &quot;7.1 clear + rebuild&quot;">​</a></h3><p>clear + rebuild 仍用于：</p><ul><li>short session 已被判定需要清理</li><li>进入 persistent-auth rebuild 主链</li></ul><h3 id="_7-2-runtime-reload-try-login" tabindex="-1">7.2 runtime reload / <code>_try_login()</code> <a class="header-anchor" href="#_7-2-runtime-reload-try-login" aria-label="Permalink to &quot;7.2 runtime reload / \`_try_login()\`&quot;">​</a></h3><p>runtime reload / <code>_try_login()</code> 当前需要按阶段理解：</p><ol><li>token load</li><li>fresh session login</li><li>candidate runtime readiness</li><li>verify</li><li>runtime swap</li></ol><p>关键约束：</p><ul><li><code>login_result=false</code> 不得继续 verify</li><li><code>candidate_runtime_account_ready=false</code> / <code>candidate_runtime_cookie_ready=false</code> 不得继续 verify</li><li>verify 失败不得污染旧 runtime</li></ul><h3 id="_7-3-当前主修补点" tabindex="-1">7.3 当前主修补点 <a class="header-anchor" href="#_7-3-当前主修补点" aria-label="Permalink to &quot;7.3 当前主修补点&quot;">​</a></h3><p>当前主修补点已经从“verify 失败”进一步收口到：</p><ul><li>login-stage 与 verify-stage 可以区分</li><li>恢复场景复用旧 session 会导致 <code>login(false)</code></li><li>改为 fresh session 后，该类主断点已被消除</li></ul><p>但这只代表：</p><ul><li><strong>fresh session 修补后的 <code>_try_login()</code> 主路径已恢复稳定</strong></li></ul><p>不代表：</p><ul><li>所有 rebuild 分支都已通过</li><li>auto runtime reload 全量通过</li><li>singleflight / fallback / cross-boundary 全量通过</li></ul><hr><h2 id="_8-状态转移口径" tabindex="-1">8. 状态转移口径 <a class="header-anchor" href="#_8-状态转移口径" aria-label="Permalink to &quot;8. 状态转移口径&quot;">​</a></h2><h3 id="_8-1-degraded-→-healthy" tabindex="-1">8.1 degraded → healthy <a class="header-anchor" href="#_8-1-degraded-→-healthy" aria-label="Permalink to &quot;8.1 degraded → healthy&quot;">​</a></h3><p>适用于：</p><ul><li>runtime reload / <code>_try_login()</code> 成功</li><li>clear+rebuild 成功</li><li>non-destructive recovery 成功</li></ul><h3 id="_8-2-degraded-→-locked" tabindex="-1">8.2 degraded → locked <a class="header-anchor" href="#_8-2-degraded-→-locked" aria-label="Permalink to &quot;8.2 degraded → locked&quot;">​</a></h3><p>只在：</p><ul><li>长期态缺失</li><li>或等价硬故障导致自动恢复前提已经不存在</li></ul><h3 id="_8-3-degraded-manual-login-required" tabindex="-1">8.3 degraded ≠ manual login required <a class="header-anchor" href="#_8-3-degraded-manual-login-required" aria-label="Permalink to &quot;8.3 degraded ≠ manual login required&quot;">​</a></h3><p>当前口径必须保持：</p><ul><li>degraded 只是“自动恢复仍有机会”的状态</li><li>manual login required 是更高阈值结论</li></ul><hr><h2 id="_9-可观测性与验收用途" tabindex="-1">9. 可观测性与验收用途 <a class="header-anchor" href="#_9-可观测性与验收用途" aria-label="Permalink to &quot;9. 可观测性与验收用途&quot;">​</a></h2><p>后续验收至少应关注：</p><ul><li><code>auth_short_session_clear_decision</code></li><li><code>auth_non_destructive_recovery</code></li><li><code>auth_recovery_singleflight</code></li><li><code>auth_runtime_reload</code></li><li><code>auth_mode_transition</code></li><li><code>_try_login()</code> trace 中的： <ul><li><code>login_result</code></li><li><code>candidate_runtime_account_ready</code></li><li><code>candidate_runtime_cookie_ready</code></li><li><code>verify_attempted</code></li><li><code>verify_error_text</code></li><li><code>runtime_swap_attempted</code></li><li><code>runtime_swap_applied</code></li></ul></li></ul><hr><h2 id="_10-当前已知边界" tabindex="-1">10. 当前已知边界 <a class="header-anchor" href="#_10-当前已知边界" aria-label="Permalink to &quot;10. 当前已知边界&quot;">​</a></h2><ol><li>Xiaomi 云端风控仍不可消除</li><li>系统目标仍是可恢复、可观测、可预测，而不是零失败</li><li>当前 fresh session 修补只覆盖 <code>_try_login()</code> 主路径</li><li>singleflight 是否已在线上充分闭环，仍需独立验收</li><li>fallback path 仍需独立验收，不应借主路径结论代替</li><li>auth / playback 交叉边界仍未纳入本轮通过范围</li></ol><hr><h2 id="_11-与现有文档关系" tabindex="-1">11. 与现有文档关系 <a class="header-anchor" href="#_11-与现有文档关系" aria-label="Permalink to &quot;11. 与现有文档关系&quot;">​</a></h2><ul><li>当前 auth runtime 主线路径，以 <code>docs/spec/auth_runtime_recovery.md</code> 为主</li><li>当前 runtime reload / <code>_try_login()</code> 阶段边界，以 <code>docs/spec/auth_runtime_reload_recovery_path.md</code> 为主</li><li>当前 auto runtime reload 验收边界，以 <code>docs/spec/auth_auto_runtime_reload_acceptance.md</code> 为主</li><li>本文档负责状态机语义收口，不提供 spec rebuild 总通过结论</li></ul>`,95)]))}const _=a(o,[["render",t]]);export{p as __pageData,_ as default};
